# module_shapes: Geometric shapes with inheritance and interfaces

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3

interface IDrawable:
    def draw(self) -> str: ...

interface IMeasurable:
    def area(self) -> float: ...
    def perimeter(self) -> float: ...

@abstract
class Shape(IDrawable, IMeasurable):
    color: Color

    def __init__(self, color: Color):
        self.color = color

    def get_color_name(self) -> str:
        return self.color.name

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color):
        super().__init__(color)
        self.width = width
        self.height = height

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def draw(self) -> str:
        return f"Rectangle({self.width}, {self.height})"

class Circle(Shape):
    radius: float
    PI: float = 3.14159

    def __init__(self, radius: float, color: Color):
        super().__init__(color)
        self.radius = radius

    def area(self) -> float:
        return self.PI * self.radius ** 2.0

    def perimeter(self) -> float:
        return 2.0 * self.PI * self.radius

    def draw(self) -> str:
        return f"Circle(r={self.radius})"

def compare_areas(s1: Shape, s2: Shape) -> str:
    a1: float = s1.area()
    a2: float = s2.area()
    if a1 > a2:
        return "first"
    elif a2 > a1:
        return "second"
    else:
        return "equal"

