# module_utils: Utility types and functions

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_from_origin(self) -> float:
        return (self.x ** 2.0 + self.y ** 2.0) ** 0.5

struct Dimension:
    width: float
    height: float

@static
class ShapeFactory:
    _counter: int = 0

    @static
    def create_square(size: float) -> tuple[Dimension, Point]:
        dim: Dimension = Dimension()
        dim.width = size
        dim.height = size
        center: Point = Point(size / 2.0, size / 2.0)
        return dim, center

    @static
    def increment_counter() -> int:
        ShapeFactory._counter = ShapeFactory._counter + 1
        return ShapeFactory._counter

def format_measurement(value: float, unit: str) -> str:
    formatted: str = f"{value:.2f}{unit}"
    return formatted

def calculate_diagonal(rect: Dimension) -> float:
    return (rect.width ** 2.0 + rect.height ** 2.0) ** 0.5
